// Transaction.java
public class Transaction {
    private String id;
    private double amount;
    private String type;

    public Transaction(String id, double amount, String type) {
        this.id = id;
        this.amount = amount;
        this.type = type;
    }

    public String getId() {
        return id;
    }

    public void setId(String id) {
        this.id = id;
    }

    public double getAmount() {
        return amount;
    }

    public void setAmount(double amount) {
        this.amount = amount;
    }

    public String getType() {
        return type;
    }

    public void setType(String type) {
        this.type = type;
    }
}

// Account.java
public class Account {
    private double balance;

    public Account() {
        this.balance = 0.0;
    }

    public double getBalance() {
        return balance;
    }

    public void setBalance(double balance) {
        this.balance = balance;
    }

    public void deposit(double amount) {
        balance += amount;
    }

    public void withdraw(double amount) {
        if (balance >= amount) {
            balance -= amount;
        } else {
            System.out.println("Insufficient funds");
        }
    }
}

// BankingApp.java
public class BankingApp extends AppCompatActivity {
    private Account account;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        account = new Account();

        // Initialize UI components
        Button depositButton = findViewById(R.id.deposit_button);
        Button withdrawButton = findViewById(R.id.withdraw_button);
        TextView balanceTextView = findViewById(R.id.balance_text_view);

        // Set up button listeners
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                Intent intent = new Intent(BankingApp.this, DepositActivity.class);
                startActivity(intent);
            }
        });

        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                Intent intent = new Intent(BankingApp.this, WithdrawActivity.class);
                startActivity(intent);
            }
        });
    }

    // Method to display account balance in UI
    private void updateBalanceTextView() {
        TextView balanceTextView = findViewById(R.id.balance_text_view);
        balanceTextView.setText(String.valueOf(account.getBalance()));
    }
}

// DepositActivity.java
public class DepositActivity extends AppCompatActivity {
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_deposit);

        // Initialize UI components
        Button depositButton = findViewById(R.id.deposit_button);
        EditText amountEditText = findViewById(R.id.amount_edit_text);

        // Set up button listener
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                String amountStr = amountEditText.getText().toString();
                double amount = Double.parseDouble(amountStr);

                account.deposit(amount);
                updateBalanceTextView();

                finish();
            }
        });
    }

    // Method to display account balance in UI
    private void updateBalanceTextView() {
        Intent intent = new Intent(DepositActivity.this, BankingApp.class);
        setResult(RESULT_OK, intent);
        finish();
    }
}

